/**
 * Build a session title for the CC prompt bar (CC 2.1.94 sessionTitle).
 *
 * Format: `{branch}` or `{branch} [worktree]` or `{branch} · {effort}`.
 * Bounded to 60 chars to fit narrow prompt bars. Returns empty string when
 * there's nothing meaningful to surface (no branch, no effort override).
 *
 * Why branch: branch is the single most useful session identifier — it
 * answers "which feature am I on" at a glance in the prompt bar and the
 * --resume picker. Effort is only appended when it differs from the
 * CC 2.1.94 default ('high') so the default case stays uncluttered.
 *
 * CC 2.1.97: worktree indicator appended when cwd is a linked git worktree,
 * matching the workspace.git_worktree field in StatusLine JSON.
 */
function buildSessionTitle(branch: string, effort: string, isWorktree = false): string {
  const cleanBranch = (branch || '').trim().replace(/[\r\n]+/g, ' ');
  // 'unknown' is git.ts's fallback sentinel when branch detection fails (not a
  // git repo / detached / git missing). It must NOT leak into the prompt-bar
  // title as a "… · unknown" suffix — treat it as no branch so the title is
  // just the AI topic (or empty). Seen in the wild: "SDLC Roadmap · unknown".
  if (!cleanBranch || cleanBranch === 'unknown') return '';
  // Strip common branch prefixes to save characters in the title bar
  const shortBranch = cleanBranch
    .replace(/^(refs\/heads\/|origin\/)/, '')
    .slice(0, 40);
  const parts = [shortBranch];
  if (isWorktree) {
    parts.push('wt');
  }
  if (effort && effort !== DEFAULT_EFFORT_LEVEL) {
    parts.push(effort);
  }
  return parts.join(' · ').slice(0, 60);
}

/**
 * Decide whether to emit `sessionTitle` for this turn.
 *
 * Why this exists: CC 2.1.94 lets hooks set the prompt-bar title via
 * `hookSpecificOutput.sessionTitle`. If we emit it on every turn,
 * we silently overwrite any title the user set with `/rename` — the user's
 * value differs from our branch-derived value, so CC re-asserts ours and
 * the rename disappears within one prompt.
 *
 * Fix: emit only when the computed title differs from the title we
 * emitted on the previous turn. Mirrors the prompt-hash.txt delta-skip
 * pattern below (line ~324). Combined with getPinnedBranch() (title sourced
 * from the session's first-seen branch, not the live working-tree branch),
 * `/rename` sticks indefinitely even under concurrent-session branch thrash.
 *
 * Returns true on first turn (no state file), on branch/effort change, or on
 * I/O failure (fail-open keeps prior behavior).
 */
function shouldEmitSessionTitle(
  title: string,
  sessionId: string | undefined,
  projectDir: string | undefined,
): boolean {
  if (!title) return false;
  if (!sessionId || !projectDir) return true;
  try {
    const dir = getPromptSessionDir(sessionId, projectDir);
    const file = join(dir, 'last-session-title.txt');
    if (existsSync(file)) {
      const last = readFileSync(file, 'utf8').trim();
      if (last === title) return false;
    }
    if (!existsSync(dir)) mkdirSync(dir, { recursive: true });
    writeFileSync(file, title, 'utf8');
    return true;
  } catch {
    return true;
  }
}

/**
 * Pin the branch used for the session title to the FIRST branch this session
 * observed, persisted per-session. Subsequent turns reuse the pinned value
 * instead of re-reading the live working-tree branch.
 *
 * Why: the title was derived from `git branch --show-current` on every prompt.
 * When multiple Claude sessions share one working tree (no per-session
 * worktree), another session's `git checkout` flips the tree's branch under
 * you — so your title would re-derive to the other session's branch and
 * flip-flop turn to turn, defeating shouldEmitSessionTitle() (the branch
 * genuinely "changed" from this session's view) and clobbering any `/rename`.
 *
 * Pinning to first-seen makes the title stable under concurrent-session branch
 * thrash. Trade-off: an in-session `git checkout` by THIS session won't refresh
 * the title — acceptable, since the recommended setup is one worktree per
 * session, where the branch is constant for the session's life.
 *
 * Fail-open: returns the live branch on missing ids or any I/O error.
 */
function getPinnedBranch(
  liveBranch: string,
  sessionId: string | undefined,
  projectDir: string | undefined,
): string {
  if (!sessionId || !projectDir) return liveBranch;
  try {
    const dir = getPromptSessionDir(sessionId, projectDir);
    const file = join(dir, 'session-branch.txt');
    if (existsSync(file)) {
      const pinned = readFileSync(file, 'utf8').trim();
      if (pinned) return pinned;
    }
    // First turn for this session: pin whatever branch we see now. Don't pin
    // the 'unknown' fallback (git.ts) — git may not be ready on turn 1; leaving
    // it unpinned lets a later turn pin the real branch instead.
    if (!liveBranch || liveBranch === 'unknown') return liveBranch;
    if (!existsSync(dir)) mkdirSync(dir, { recursive: true });
    writeFileSync(file, liveBranch, 'utf8');
    return liveBranch;
  } catch {
    return liveBranch;
  }
}

/**
 * Detect noisy/low-value context that shouldn't consume token budget.
 * Returns true if the context is only bracket-enclosed markers or
 * cross-project context lines with no actionable content.
 */
function isNoisyOutput(context: string): boolean {
  const lines = context.split('\n').filter(l => l.trim().length > 0);
  if (lines.length === 0) return true;

  return lines.every(line => {
    const trimmed = line.trim();
    // [Cross-project context:...] lines
    if (/^\[Cross-project context:.*\]$/.test(trimmed)) return true;
    // Bracket-enclosed timestamp markers like [2026-02-28 08:45]
    if (/^\[\d{4}-\d{2}-\d{2}\s+\d{2}:\d{2}.*\]$/.test(trimmed)) return true;
    return false;
  });
}

// -----------------------------------------------------------------------------
// Dispatcher Implementation
// -----------------------------------------------------------------------------

/**
 * Unified dispatcher that runs all every-turn UserPromptSubmit hooks
 * and consolidates their output into a single additionalContext response.
 */
export function unifiedPromptDispatcher(input: HookInput, ctx: HookContext = NOOP_CTX): HookResult {
  // Guard: skip all processing for oversized or binary prompts (image paste, base64 data)
  const prompt = input.prompt || '';
  if (prompt.length > MAX_PROMPT_LENGTH) {
    ctx.log(HOOK_NAME, `Prompt too large (${prompt.length} chars > ${MAX_PROMPT_LENGTH}), skipping — likely image/binary data`);
    return outputSilentSuccess();
  }
  if (prompt.length > 500 && isImageOrBinaryPrompt(prompt)) {
    ctx.log(HOOK_NAME, `Image/binary content detected in prompt (${prompt.length} chars), skipping text analysis hooks`);
    return outputSilentSuccess();
  }

  const contextParts: string[] = [];
  let totalTokens = 0;

  // Effort-aware budget (CC 2.1.76): /effort low → 200t, medium → 800t, high → 1200t
  // CC 2.1.94 changed default effort from 'medium' → 'high' for most user tiers.
  const effort = detectEffortLevel(input);
  const tokenBudget = effortTokenBudget(effort, MAX_OUTPUT_TOKENS);
  if (effort !== DEFAULT_EFFORT_LEVEL) {
    ctx.log(HOOK_NAME, `Effort level: ${effort} → token budget: ${tokenBudget}t`);
  }

  // Resolve session/project for once-flag tracking
  const sessionId = input.session_id || (ctx.sessionId);
  const projectDir = input.project_dir || (ctx.projectDir);

  for (const hook of HOOKS) {
    try {
      // Low effort: skip once-per-session context hooks (handoffs, etc.) — they're heavy
      if (effort === 'low' && hook.runOnce && hook.producesContext) {
        ctx.log(HOOK_NAME, `${hook.name}: skipped at low effort`);
        continue;
      }

      // Once-per-session gate: skip if already run this session
      if (hook.runOnce) {
        if (!sessionId) {
          // No session_id available — allow re-run (same as legacy behavior)
          ctx.log(HOOK_NAME, `${hook.name}: no session_id, running without once-gate`);
        } else if (hasOnceFlagRun(hook.name, sessionId, projectDir)) {
          ctx.log(HOOK_NAME, `${hook.name}: already ran this session, skipping`);
          continue;
        }
      }

      const result = hook.fn(input, ctx);

      // Mark once-per-session hook as done after successful execution
      if (hook.runOnce && sessionId) {
        try {
          setOnceFlagDone(hook.name, sessionId, projectDir);
        } catch (flagErr) {
          ctx.log(HOOK_NAME, `${hook.name}: failed to write once-flag: ${flagErr}`, 'warn');
        }
      }

      // Skip silent analytics hooks — they've done their work (logging/tracking)
      if (!hook.producesContext) {
        continue;
      }

      // Extract context from the result
      const context = extractContext(result);
      if (!context) {
        continue;
      }

      // Filter noisy/low-value context before consuming budget
      if (isNoisyOutput(context)) {
        ctx.log(HOOK_NAME, `${hook.name}: noisy output filtered`);
        continue;
      }

      // Budget check: don't exceed effort-adjusted token budget
      const contextTokens = estimateTokenCount(context);
      if (totalTokens + contextTokens > tokenBudget) {
        ctx.log(HOOK_NAME, `Budget limit: skipping ${hook.name} (${contextTokens}t would exceed ${tokenBudget}t cap, effort=${effort})`);
        continue;
      }

      contextParts.push(context);
      totalTokens += contextTokens;

      ctx.log(HOOK_NAME, `${hook.name}: +${contextTokens}t (total: ${totalTokens}t)`);
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      ctx.log(HOOK_NAME, `${hook.name} failed: ${message}`, 'warn');
    }
  }

  // Build the session title (CC 2.1.94) and decide whether to emit it.
  // Delta-skip: emit only when the title differs from the previous turn so
  // we don't overwrite `/rename`. The CC "identical = no-op" claim only
  // covers repeats of OUR value — a user `/rename` changes the live title
  // to something else, which makes our next emit a clobbering override.
  // Pin to the session's first-seen branch so concurrent-session branch thrash
  // (shared working tree) can't flip the title turn-to-turn or clobber /rename.
  const titleBranch = getPinnedBranch(ctx.branch, sessionId, projectDir);
  const branchTitle = buildSessionTitle(titleBranch, effort, ctx.isWorktree);

  // Session identity (haiku auto-rename + auto-color): turn 1 spawns a
  // detached, context-stripped `claude -p --model haiku` (RC2) and appends a
  // hash-based agent-color record to the transcript; the generated title is
  // adopted on turn 1 (opt-in inline wait, RC1) or the next turn, carrying the
  // color as an emoji prefix (RC3, since hooks can't set live color). The
  // returned string is already emoji-prefixed; we merge it in front of the
  // branch title. Fails open to branch-only title.
  const aiTitle = sessionId
    ? manageSessionIdentity(input, ctx, getPromptSessionDir(sessionId, projectDir), projectDir)
    : null;
  const sessionTitle = aiTitle ? mergeIdentityTitle(aiTitle, branchTitle) : branchTitle;
  const emitTitle = shouldEmitSessionTitle(sessionTitle, sessionId, projectDir);

  // No context produced — still try to set the title if we have one
  if (contextParts.length === 0) {
    if (emitTitle) {
      return outputPromptContextWithTitle('', sessionTitle);
    }
    return outputSilentSuccess();
  }

  // Single consolidated output
  const consolidated = contextParts.join('\n\n---\n\n');

  // Delta detection: skip injection if consolidated output is unchanged from last turn (#token-reduction)
  // Note: the title is still emitted on delta-skip turns because it's cheap
  // and ensures the prompt bar stays current even when context is cached.
  const consolidatedHash = fnv1aHash(consolidated);
  const hashDir = getPromptSessionDir(sessionId, projectDir);
  const hashFile = join(hashDir, 'prompt-hash.txt');

  try {
    if (existsSync(hashFile)) {
      const lastHash = readFileSync(hashFile, 'utf8').trim();
      if (lastHash === consolidatedHash) {
        ctx.log(HOOK_NAME, `Delta skip: consolidated output unchanged (hash=${consolidatedHash})`);
        if (emitTitle) {
          return outputPromptContextWithTitle('', sessionTitle);
        }
        return outputSilentSuccess();
      }
    }
    // Write new hash
    if (!existsSync(hashDir)) {
      mkdirSync(hashDir, { recursive: true });
    }
    writeFileSync(hashFile, consolidatedHash, 'utf8');
  } catch (err) {
    ctx.log(HOOK_NAME, `Delta detection error: ${err}`, 'warn');
    // Proceed with injection on error
  }

  ctx.log(HOOK_NAME, `Consolidated ${contextParts.length} hooks into ${totalTokens}t${emitTitle ? ` · title="${sessionTitle}"` : sessionTitle ? ' · title=(skipped, unchanged)' : ''}`);

  // Track token usage for budget enforcement
  if (totalTokens > 0) {
    trackTokenUsage(HOOK_NAME, 'prompt', totalTokens);
  }

  if (emitTitle) {
    return outputPromptContextWithTitle(consolidated, sessionTitle);
  }
  return outputPromptContext(consolidated);
}
